INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A1', 'listening', 'Minimal Pairs', 'Distinguish between similar sounds.', '{"type":"listen_and_choose","instructions":"Listen and choose the word you hear.","exercises":[{"prompt":"ship","question":"Which word sounds like a boat?","options":["ship","sheep"],"correct":0,"hint":"Short ''i'' sound."},{"prompt":"sheep","question":"Which word is a farm animal?","options":["ship","sheep"],"correct":1,"hint":"Long ''ee'' sound."},{"prompt":"bat","question":"Which word is used in baseball?","options":["bat","bet"],"correct":0,"hint":"Short ''a'' sound."},{"prompt":"bet","question":"Which word means to gamble?","options":["bat","bet"],"correct":1,"hint":"Short ''e'' sound."},{"prompt":"fan","question":"Which word keeps you cool?","options":["fan","van"],"correct":0,"hint":"Starts with ''f''."},{"prompt":"pin","question":"Which word is used to attach items together?","options":["pin","pen"],"correct":0,"hint":"Short ''i'' sound."},{"prompt":"pen","question":"Which word is used for writing?","options":["pin","pen"],"correct":1,"hint":"Short ''e'' sound."},{"prompt":"cat","question":"Which word is a common pet?","options":["cat","cut"],"correct":0,"hint":"Short ''a'' sound."},{"prompt":"cut","question":"Which word means to slice something?","options":["cat","cut"],"correct":1,"hint":"Short ''u'' sound."},{"prompt":"wait","question":"Which word means to stay in one place?","options":["wait","weight"],"correct":0,"hint":"Long ''a'' sound."},{"prompt":"weight","question":"Which word refers to how heavy something is?","options":["wait","weight"],"correct":1,"hint":"Long ''a'' followed by ''t'' sound."},{"prompt":"bark","question":"Which word is the sound a dog makes?","options":["bark","park"],"correct":0,"hint":"Short ''a'' sound."},{"prompt":"park","question":"Which word is a place to play outside?","options":["bark","park"],"correct":1,"hint":"Short ''a'' followed by ''r'' sound."},{"prompt":"fur","question":"Which word describes an animal coat?","options":["fur","far"],"correct":0,"hint":"Short ''u'' sound."},{"prompt":"far","question":"Which word indicates a long distance?","options":["fur","far"],"correct":1,"hint":"Short ''a'' sound."},{"prompt":"bowl","question":"Which word is used to hold food?","options":["bowl","ball"],"correct":0,"hint":"Long ''o'' sound."},{"prompt":"ball","question":"Which word refers to a round object used in games?","options":["bowl","ball"],"correct":1,"hint":"Short ''a'' sound."},{"prompt":"light","question":"Which word means something that illuminates?","options":["light","lite"],"correct":0,"hint":"Long ''i'' sound."},{"prompt":"lite","question":"Which word refers to something low in calories?","options":["light","lite"],"correct":1,"hint":"Long ''i'' sound but shorter."},{"prompt":"nest","question":"Which word is a home for birds?","options":["nest","net"],"correct":0,"hint":"Short ''e'' sound."},{"prompt":"net","question":"Which word is used for catching fish?","options":["nest","net"],"correct":1,"hint":"Short ''e'' sound."}]}', 11),
('en', 'A1', 'listening', 'The Grocery Store', 'Listen to items being bought.', '{"type":"listen_and_choose","instructions":"Which item is being described?","exercises":[{"prompt":"A dozen red apples.","question":"How many apples?","options":["6","10","12"],"correct":2,"hint":"A dozen means twelve."},{"prompt":"A loaf of fresh bread.","question":"What is being bought?","options":["milk","bread","cheese"],"correct":1,"hint":"You slice this for sandwiches."},{"prompt":"A carton of orange juice.","question":"What container is mentioned?","options":["bottle","carton","bag"],"correct":1,"hint":"Starts with C."},{"prompt":"Two kilograms of sugar.","question":"What is the weight?","options":["1kg","2kg","3kg"],"correct":1,"hint":"Listen for the number."},{"prompt":"A bunch of yellow bananas.","question":"What color are the fruits?","options":["green","red","yellow"],"correct":2,"hint":"Common banana color."},{"prompt":"A bunch of ripe bananas.","question":"What fruit is being described?","options":["apples","bananas","oranges"],"correct":1,"hint":"These are yellow and curved."},{"prompt":"A bottle of sparkling water.","question":"What type of drink is mentioned?","options":["juice","soda","water"],"correct":2,"hint":"You can find bubbles in this drink."},{"prompt":"A packet of pasta.","question":"What food item is being referred to?","options":["rice","pasta","bread"],"correct":1,"hint":"You cook this in boiling water."},{"prompt":"A jar of peanut butter.","question":"What is stored in the jar?","options":["jam","peanut butter","honey"],"correct":1,"hint":"This is often spread on bread."},{"prompt":"A slice of chocolate cake.","question":"What dessert is mentioned?","options":["pie","cake","cookies"],"correct":1,"hint":"This is often served at birthdays."},{"prompt":"A cup of hot coffee.","question":"What beverage is being described?","options":["tea","coffee","milk"],"correct":1,"hint":"This drink keeps many people awake."},{"prompt":"A bag of chips.","question":"What snack is being referred to?","options":["nuts","crackers","chips"],"correct":2,"hint":"These are often crunchy and salty."},{"prompt":"A carton of milk.","question":"What dairy product is mentioned?","options":["cream","milk","yogurt"],"correct":1,"hint":"You pour this over cereal."},{"prompt":"A bowl of cereal.","question":"What is being served?","options":["soup","salad","cereal"],"correct":2,"hint":"You usually eat this for breakfast."},{"prompt":"A tin of cookies.","question":"What treat is being described?","options":["brownies","candy","cookies"],"correct":2,"hint":"These are often sweet and baked."},{"prompt":"A plate of sushi.","question":"What type of food is mentioned?","options":["sushi","pasta","sandwich"],"correct":0,"hint":"This is a Japanese dish with rice."},{"prompt":"A basket of strawberries.","question":"What fruit is described?","options":["strawberries","blueberries","raspberries"],"correct":0,"hint":"These are red and sweet."},{"prompt":"A scoop of ice cream.","question":"What dessert is being mentioned?","options":["cake","ice cream","pudding"],"correct":1,"hint":"This is cold and comes in many flavors."},{"prompt":"A glass of lemonade.","question":"What drink is described?","options":["tea","lemonade","soda"],"correct":1,"hint":"This is often refreshing in summer."}]}', 12),
('en', 'A1', 'listening', 'Daily Routine Times', 'Listen to times for daily tasks.', '{"type":"listen_and_choose","instructions":"At what time does the action happen?","exercises":[{"prompt":"I wake up at half past six.","question":"Wake up time?","options":["6:00","6:30","7:00"],"correct":1,"hint":"Half past means :30."},{"prompt":"Breakfast is at quarter to eight.","question":"Breakfast time?","options":["7:15","7:45","8:15"],"correct":1,"hint":"Quarter to means :45."},{"prompt":"I go to work at eight fifteen.","question":"Work time?","options":["8:15","8:50","9:15"],"correct":0,"hint":"Eight plus fifteen."},{"prompt":"Lunch is at exactly noon.","question":"Lunch time?","options":["11:00","12:00","13:00"],"correct":1,"hint":"Noon is midday."},{"prompt":"I get home at five o''clock.","question":"Home time?","options":["16:00","17:00","18:00"],"correct":1,"hint":"5:00."},{"prompt":"I have lunch at one o''clock.","question":"Lunch time?","options":["12:00","1:00","2:00"],"correct":1,"hint":"One o''clock means 1:00."},{"prompt":"My class starts at nine thirty.","question":"Class start time?","options":["9:00","9:30","10:00"],"correct":1,"hint":"Nine plus thirty."},{"prompt":"Dinner is at six o''clock.","question":"Dinner time?","options":["5:00","6:00","7:00"],"correct":1,"hint":"Six o''clock means 6:00."},{"prompt":"I go to bed at ten thirty.","question":"Bedtime?","options":["10:00","10:30","11:00"],"correct":1,"hint":"Ten plus thirty."},{"prompt":"The movie starts at seven fifteen.","question":"Movie start time?","options":["7:00","7:15","7:30"],"correct":1,"hint":"Seven plus fifteen."},{"prompt":"I exercise at five o''clock.","question":"Exercise time?","options":["4:00","5:00","6:00"],"correct":1,"hint":"Five o''clock means 5:00."},{"prompt":"My meeting is at three thirty.","question":"Meeting time?","options":["3:00","3:30","4:00"],"correct":1,"hint":"Three plus thirty."},{"prompt":"I wake up at six fifteen.","question":"Wake up time?","options":["6:00","6:15","6:30"],"correct":1,"hint":"Six plus fifteen."},{"prompt":"The store opens at eight o''clock.","question":"Store opening time?","options":["7:00","8:00","9:00"],"correct":1,"hint":"Eight o''clock means 8:00."},{"prompt":"I finish work at five fifteen.","question":"Finish work time?","options":["5:00","5:15","5:30"],"correct":1,"hint":"Five plus fifteen."},{"prompt":"I have a meeting at two o''clock.","question":"Meeting time?","options":["1:00","2:00","3:00"],"correct":1,"hint":"Two o''clock means 2:00."},{"prompt":"The class ends at four thirty.","question":"Class end time?","options":["4:00","4:30","5:00"],"correct":1,"hint":"Four plus thirty."},{"prompt":"I usually read at nine o''clock.","question":"Reading time?","options":["8:00","9:00","10:00"],"correct":1,"hint":"Nine o''clock means 9:00."},{"prompt":"The train departs at six forty-five.","question":"Train departure time?","options":["6:15","6:45","7:15"],"correct":1,"hint":"Forty-five minutes past six."},{"prompt":"I call my friend at eight thirty.","question":"Call time?","options":["8:00","8:30","9:00"],"correct":1,"hint":"Eight plus thirty."}]}', 13),
('en', 'A1', 'listening', 'Complex Directions', 'Listen to 2-step directions.', '{"type":"listen_and_choose","instructions":"What is the first step?","exercises":[{"prompt":"Go straight and then turn left.","question":"First action?","options":["Turn left","Go straight","Stop"],"correct":1,"hint":"Go straight comes first."},{"prompt":"Turn right at the bank and stop.","question":"Where to turn?","options":["At the park","At the bank","At the station"],"correct":1,"hint":"Listen for the building."},{"prompt":"Walk two blocks and look for the red door.","question":"Keep walking for how long?","options":["1 block","2 blocks","3 blocks"],"correct":1,"hint":"Listen for the number."},{"prompt":"Take the bus and get off at the third stop.","question":"Which stop?","options":["1st","2nd","3rd"],"correct":2,"hint":"Ordinal number."},{"prompt":"Cross the street and wait by the tree.","question":"Where to wait?","options":["By the tree","In the shop","At the bus stop"],"correct":0,"hint":"Outdoor nature object."},{"prompt":"Take the first right after the gas station.","question":"When to turn right?","options":["After the grocery store","After the gas station","Before the gas station"],"correct":1,"hint":"Listen for the location of the turn."},{"prompt":"Cross the street and then find the library.","question":"What is the first action?","options":["Find the library","Cross the street","Turn around"],"correct":1,"hint":"The action comes first."},{"prompt":"Walk towards the fountain and turn left.","question":"Where to walk towards?","options":["The fountain","The statue","The bench"],"correct":0,"hint":"Listen for the landmark."},{"prompt":"Go back to the traffic light and turn right.","question":"What to do at the traffic light?","options":["Stop","Turn left","Turn right"],"correct":2,"hint":"Listen for the direction."},{"prompt":"After the next block, stop at the corner.","question":"What to do after the next block?","options":["Stop","Turn","Continue"],"correct":0,"hint":"Listen for the action to take."},{"prompt":"Head towards the post office and walk straight.","question":"What to walk towards?","options":["The park","The post office","The bank"],"correct":1,"hint":"Listen for the destination."},{"prompt":"Turn left at the traffic circle and go straight.","question":"Where to turn?","options":["At the traffic lights","At the traffic circle","At the intersection"],"correct":1,"hint":"Listen for the type of junction."},{"prompt":"Go past the supermarket and then turn right.","question":"What to do after passing the supermarket?","options":["Turn left","Turn right","Stop"],"correct":1,"hint":"Listen for the direction after passing."},{"prompt":"Walk three blocks and turn right at the cafe.","question":"How many blocks to walk?","options":["1 block","2 blocks","3 blocks"],"correct":2,"hint":"Listen for the number of blocks."},{"prompt":"Take the second exit at the roundabout.","question":"What to do at the roundabout?","options":["Take the first exit","Take the second exit","Go straight"],"correct":1,"hint":"Listen for which exit to take."},{"prompt":"Go left at the light and continue straight.","question":"Which direction to go at the light?","options":["Right","Left","Straight"],"correct":1,"hint":"Listen for the direction to take."},{"prompt":"Walk straight until you see the school.","question":"What should you look for?","options":["The library","The school","The bank"],"correct":1,"hint":"Listen for the landmark."},{"prompt":"After the bridge, turn left and walk one block.","question":"What to do after the bridge?","options":["Turn right","Turn left","Continue straight"],"correct":1,"hint":"Listen for the direction after the bridge."},{"prompt":"Stop at the crosswalk and then turn right.","question":"Where to stop?","options":["At the stop sign","At the traffic light","At the crosswalk"],"correct":2,"hint":"Listen for the specific location."},{"prompt":"Proceed to the end of the street and turn left.","question":"What to do at the end of the street?","options":["Turn right","Turn left","Continue straight"],"correct":1,"hint":"Listen for the action at the end."}]}', 14),
('en', 'A1', 'listening', 'Ordering Drinks', 'Listen to coffee shop orders.', '{"type":"listen_and_choose","instructions":"What did the customer order?","exercises":[{"prompt":"A large latte with sugar.","question":"Size of the drink?","options":["small","medium","large"],"correct":2,"hint":"Biggest size."},{"prompt":"A small espresso, no milk.","question":"Is there milk?","options":["yes","no"],"correct":1,"hint":"No milk mentioned."},{"prompt":"Two medium teas with lemon.","question":"How many drinks?","options":["1","2","3"],"correct":1,"hint":"Listen for quantity."},{"prompt":"An iced coffee with cream.","question":"Temperature?","options":["hot","iced"],"correct":1,"hint":"Cold drink."},{"prompt":"A hot chocolate with marshmallows.","question":"What is the topping?","options":["cream","chocolate","marshmallows"],"correct":2,"hint":"White fluffy sweets."},{"prompt":"A medium cappuccino with oat milk.","question":"What type of milk is used?","options":["whole","oat","almond"],"correct":1,"hint":"Listen for the type of milk."},{"prompt":"Three large black coffees, no sugar.","question":"How many coffees?","options":["1","2","3"],"correct":2,"hint":"Listen for the quantity mentioned."},{"prompt":"A small mocha with whipped cream.","question":"What is added to the drink?","options":["sugar","milk","whipped cream"],"correct":2,"hint":"Listen for the extra topping."},{"prompt":"Two large iced teas with peach flavor.","question":"What flavor is the tea?","options":["lemon","peach","mint"],"correct":1,"hint":"Focus on the flavor mentioned."},{"prompt":"A medium flat white with cinnamon.","question":"What spice is included?","options":["nutmeg","cinnamon","vanilla"],"correct":1,"hint":"Listen for the spice added."},{"prompt":"A small caramel macchiato.","question":"What type of drink is it?","options":["latte","espresso","macchiato"],"correct":2,"hint":"The drink type is in the name."},{"prompt":"A large hot chocolate with marshmallows.","question":"What topping is added?","options":["sprinkles","marshmallows","whipped cream"],"correct":1,"hint":"Listen for the topping mentioned."},{"prompt":"Two small smoothies, one banana and one berry.","question":"What flavors are the smoothies?","options":["banana and mango","banana and berry","berry and peach"],"correct":1,"hint":"Listen for the specific flavors."},{"prompt":"A medium chai latte with no sugar.","question":"Is there sugar in the drink?","options":["yes","no"],"correct":1,"hint":"Focus on the mention of sugar."},{"prompt":"A small vanilla latte with a shot of espresso.","question":"What flavor is in the latte?","options":["chocolate","vanilla","caramel"],"correct":1,"hint":"Listen for the flavor in the drink."},{"prompt":"A large iced coffee with cream.","question":"What is added to the iced coffee?","options":["sugar","cream","milk"],"correct":1,"hint":"Listen for the additive."},{"prompt":"A medium herbal tea with honey.","question":"What sweetener is included?","options":["sugar","honey","agave"],"correct":1,"hint":"Focus on the type of sweetener."},{"prompt":"Two large lattes with almond milk.","question":"What type of milk is used in the lattes?","options":["soy","almond","oat"],"correct":1,"hint":"Listen for the milk type."},{"prompt":"A small berry smoothie with yogurt.","question":"What is added to the smoothie?","options":["milk","yogurt","ice cream"],"correct":1,"hint":"Focus on the added ingredient."},{"prompt":"A medium green tea with lemon.","question":"What is added to the green tea?","options":["honey","milk","lemon"],"correct":2,"hint":"Listen for the addition to the tea."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A1', 'speaking', 'Polite Introductions', 'Practice polite ways to meet people.', '{"type":"speak_and_repeat","instructions":"Repeat the polite phrase clearly.","exercises":[{"prompt":"Hello, it is a pleasure to meet you.","expected":"Hello it is a pleasure to meet you","hint":"Formal introduction."},{"prompt":"Could you tell me your name, please?","expected":"Could you tell me your name please","hint":"Polite question."},{"prompt":"I would like to introduce my friend, Sarah.","expected":"I would like to introduce my friend Sarah","hint":"Introducing others."},{"prompt":"Nice to see you again after a long time.","expected":"Nice to see you again after a long time","hint":"Greeting an old friend."},{"prompt":"May I have your phone number?","expected":"May I have your phone number","hint":"Asking for contact info."},{"prompt":"Thank you for your help.","expected":"Thank you for your help","hint":"Expressing gratitude."},{"prompt":"Would you mind closing the window, please?","expected":"Would you mind closing the window please","hint":"Polite request."},{"prompt":"I appreciate your understanding.","expected":"I appreciate your understanding","hint":"Showing appreciation."},{"prompt":"Could I have a glass of water, please?","expected":"Could I have a glass of water please","hint":"Making a polite request."},{"prompt":"It would be great to see you again.","expected":"It would be great to see you again","hint":"Expressing desire for a meeting."},{"prompt":"Please let me know if you need anything.","expected":"Please let me know if you need anything","hint":"Offering assistance."},{"prompt":"Excuse me, could you help me with this?","expected":"Excuse me could you help me with this","hint":"Request for assistance."},{"prompt":"I am grateful for your support.","expected":"I am grateful for your support","hint":"Thanking someone for their help."},{"prompt":"Would you like to join us for dinner?","expected":"Would you like to join us for dinner","hint":"Inviting someone."},{"prompt":"I''m sorry for the inconvenience.","expected":"I''m sorry for the inconvenience","hint":"Apologizing."},{"prompt":"May I ask you a question?","expected":"May I ask you a question","hint":"Polite inquiry."},{"prompt":"I hope you have a wonderful day.","expected":"I hope you have a wonderful day","hint":"Wishing someone well."},{"prompt":"Thank you for your kind words.","expected":"Thank you for your kind words","hint":"Acknowledging compliments."},{"prompt":"Could you please repeat that?","expected":"Could you please repeat that","hint":"Requesting clarification."},{"prompt":"It''s a pleasure to assist you.","expected":"It''s a pleasure to assist you","hint":"Offering help."}]}', 11),
('en', 'A1', 'speaking', 'At the Doctor''s', 'Practice basic medical symptoms.', '{"type":"speak_and_repeat","instructions":"State your symptom clearly.","exercises":[{"prompt":"I have a very bad headache today.","expected":"I have a very bad headache today","hint":"Pain in the head."},{"prompt":"My stomach hurts after eating lunch.","expected":"My stomach hurts after eating lunch","hint":"Digestive pain."},{"prompt":"I feel a bit dizzy and tired.","expected":"I feel a bit dizzy and tired","hint":"Not feeling steady."},{"prompt":"I have a sore throat and a cough.","expected":"I have a sore throat and a cough","hint":"Cold symptoms."},{"prompt":"Could I see the doctor this afternoon?","expected":"Could I see the doctor this afternoon","hint":"Requesting appointment."},{"prompt":"I have a sore throat and it''s hard to swallow.","expected":"I have a sore throat and it''s hard to swallow","hint":"Pain when eating or drinking."},{"prompt":"My back is hurting after sitting for too long.","expected":"My back is hurting after sitting for too long","hint":"Discomfort in the spine."},{"prompt":"I feel really congested and can''t breathe well.","expected":"I feel really congested and can''t breathe well","hint":"Nasal blockage."},{"prompt":"I have a persistent cough that won''t go away.","expected":"I have a persistent cough that won''t go away","hint":"Repeated throat clearing."},{"prompt":"My joints ache, especially when I move.","expected":"My joints ache, especially when I move","hint":"Pain in the knees or elbows."},{"prompt":"I feel nauseous and might throw up.","expected":"I feel nauseous and might throw up","hint":"Stomach upset."},{"prompt":"I have chills and I''m feeling very cold.","expected":"I have chills and I''m feeling very cold","hint":"Feeling cold but not in a cold place."},{"prompt":"I am experiencing sharp pain in my side.","expected":"I am experiencing sharp pain in my side","hint":"Sudden, intense discomfort."},{"prompt":"I feel extremely fatigued and can barely move.","expected":"I feel extremely fatigued and can barely move","hint":"Lack of energy."},{"prompt":"I have a rash that is itchy and red.","expected":"I have a rash that is itchy and red","hint":"Skin irritation."},{"prompt":"I am feeling very anxious and restless.","expected":"I am feeling very anxious and restless","hint":"Nervousness or unease."},{"prompt":"I have a runny nose and watery eyes.","expected":"I have a runny nose and watery eyes","hint":"Allergic reaction or cold."},{"prompt":"I feel a sharp pain in my chest when I breathe.","expected":"I feel a sharp pain in my chest when I breathe","hint":"Discomfort in the lungs."},{"prompt":"My feet hurt after walking for a long time.","expected":"My feet hurt after walking for a long time","hint":"Pain in the soles."},{"prompt":"I have a temperature and I feel feverish.","expected":"I have a temperature and I feel feverish","hint":"Elevated body heat."}]}', 12),
('en', 'A1', 'speaking', 'Giving Opinions', 'Express simple likes and dislikes.', '{"type":"speak_and_repeat","instructions":"Express your opinion clearly.","exercises":[{"prompt":"I really love eating Italian pizza.","expected":"I really love eating Italian pizza","hint":"Strong like."},{"prompt":"I don''t like watching scary movies.","expected":"I dont like watching scary movies","hint":"Dislike."},{"prompt":"Football is my favorite sport to play.","expected":"Football is my favorite sport to play","hint":"Preference."},{"prompt":"I think this book is very interesting.","expected":"I think this book is very interesting","hint":"Giving a thought."},{"prompt":"Traveling to new cities is exciting.","expected":"Traveling to new cities is exciting","hint":"Opinion on travel."},{"prompt":"I enjoy hiking in the mountains during the summer.","expected":"I enjoy hiking in the mountains during the summer","hint":"Enjoyment."},{"prompt":"I dislike doing the dishes after dinner.","expected":"I dislike doing the dishes after dinner","hint":"Displeasure."},{"prompt":"Reading mystery novels is my favorite pastime.","expected":"Reading mystery novels is my favorite pastime","hint":"Favorite activity."},{"prompt":"I absolutely love listening to classical music.","expected":"I absolutely love listening to classical music","hint":"Strong affection."},{"prompt":"I prefer tea over coffee in the morning.","expected":"I prefer tea over coffee in the morning","hint":"Choice."},{"prompt":"I can''t stand waiting in long lines.","expected":"I can''t stand waiting in long lines","hint":"Intense dislike."},{"prompt":"Baking cookies is something I really enjoy.","expected":"Baking cookies is something I really enjoy","hint":"Enjoyable activity."},{"prompt":"I find swimming in the ocean very refreshing.","expected":"I find swimming in the ocean very refreshing","hint":"Positive feeling."},{"prompt":"I don''t like spicy food at all.","expected":"I don''t like spicy food at all","hint":"Dislike."},{"prompt":"Traveling to new countries excites me.","expected":"Traveling to new countries excites me","hint":"Excitement."},{"prompt":"I really enjoy playing video games with my friends.","expected":"I really enjoy playing video games with my friends","hint":"Enjoyment."},{"prompt":"I prefer reading books rather than watching TV.","expected":"I prefer reading books rather than watching TV","hint":"Preference."},{"prompt":"I absolutely hate waking up early in the morning.","expected":"I absolutely hate waking up early in the morning","hint":"Strong dislike."},{"prompt":"I love visiting art galleries on weekends.","expected":"I love visiting art galleries on weekends","hint":"Enjoyable activity."},{"prompt":"I don''t enjoy running in the rain.","expected":"I don''t enjoy running in the rain","hint":"Dislike."}]}', 13),
('en', 'A1', 'speaking', 'Time Management', 'Talking about schedules.', '{"type":"speak_and_repeat","instructions":"State your schedule item.","exercises":[{"prompt":"I have a meeting at ten o''clock.","expected":"I have a meeting at ten oclock","hint":"Schedule time."},{"prompt":"My train leaves in twenty minutes.","expected":"My train leaves in twenty minutes","hint":"Transport timing."},{"prompt":"I am usually busy on Monday mornings.","expected":"I am usually busy on Monday mornings","hint":"General schedule."},{"prompt":"The supermarket closes at midnight.","expected":"The supermarket closes at midnight","hint":"Closing time."},{"prompt":"Let''s meet for lunch at half past one.","expected":"Lets meet for lunch at half past one","hint":"Proposal."},{"prompt":"I have a dentist appointment at three o''clock.","expected":"I have a dentist appointment at three oclock","hint":"Health-related schedule."},{"prompt":"We are having lunch at twelve thirty.","expected":"We are having lunch at twelve thirty","hint":"Meal timing."},{"prompt":"The conference starts at nine in the morning.","expected":"The conference starts at nine in the morning","hint":"Event timing."},{"prompt":"I usually work from nine to five.","expected":"I usually work from nine to five","hint":"Work hours."},{"prompt":"I go to the gym every Wednesday evening.","expected":"I go to the gym every Wednesday evening","hint":"Fitness schedule."},{"prompt":"My class begins at eight fifteen.","expected":"My class begins at eight fifteen","hint":"School timing."},{"prompt":"I have a phone call scheduled for four o''clock.","expected":"I have a phone call scheduled for four oclock","hint":"Communication timing."},{"prompt":"We are meeting our friends on Saturday afternoon.","expected":"We are meeting our friends on Saturday afternoon","hint":"Social plans."},{"prompt":"I need to submit my report by Friday.","expected":"I need to submit my report by Friday","hint":"Deadline."},{"prompt":"I take my dog for a walk every morning.","expected":"I take my dog for a walk every morning","hint":"Daily routine."},{"prompt":"The movie starts at seven thirty.","expected":"The movie starts at seven thirty","hint":"Entertainment timing."},{"prompt":"I have a flight to catch at six o''clock.","expected":"I have a flight to catch at six oclock","hint":"Travel schedule."},{"prompt":"I attend a yoga class on Thursday evenings.","expected":"I attend a yoga class on Thursday evenings","hint":"Wellness schedule."},{"prompt":"We have a family dinner planned for Sunday.","expected":"We have a family dinner planned for Sunday","hint":"Family time."},{"prompt":"I usually read before going to bed.","expected":"I usually read before going to bed","hint":"Nighttime routine."}]}', 14),
('en', 'A1', 'speaking', 'Emergency Phrases', 'Basic calls for help.', '{"type":"speak_and_repeat","instructions":"Repeat the emergency call.","exercises":[{"prompt":"Help! I lost my wallet in the park.","expected":"Help I lost my wallet in the park","hint":"Asking for help."},{"prompt":"Where is the nearest police station?","expected":"Where is the nearest police station","hint":"Location query."},{"prompt":"I need to call an ambulance quickly.","expected":"I need to call an ambulance quickly","hint":"Urgent request."},{"prompt":"Is there a pharmacy open nearby?","expected":"Is there a pharmacy open nearby","hint":"Medicine search."},{"prompt":"I am lost, can you help me?","expected":"I am lost can you help me","hint":"Personal status."},{"prompt":"There''s a fire in my building!","expected":"There''s a fire in my building","hint":"Reporting a fire emergency."},{"prompt":"I need help! Someone is hurt.","expected":"I need help Someone is hurt","hint":"Emergency assistance needed."},{"prompt":"Please send the police immediately!","expected":"Please send the police immediately","hint":"Requesting police intervention."},{"prompt":"I think someone is breaking into my house.","expected":"I think someone is breaking into my house","hint":"Reporting a potential burglary."},{"prompt":"My friend is having a seizure!","expected":"My friend is having a seizure","hint":"Medical emergency situation."},{"prompt":"I lost my phone at the bus station.","expected":"I lost my phone at the bus station","hint":"Lost item report."},{"prompt":"There''s been an accident on the highway.","expected":"There''s been an accident on the highway","hint":"Reporting a traffic incident."},{"prompt":"I feel unsafe, please send help.","expected":"I feel unsafe please send help","hint":"Feeling unsafe and requesting help."},{"prompt":"I can''t breathe, I need help!","expected":"I can''t breathe I need help","hint":"Serious medical condition."},{"prompt":"Someone is chasing me!","expected":"Someone is chasing me","hint":"Reporting a potential threat."},{"prompt":"My child is missing!","expected":"My child is missing","hint":"Reporting a missing person."},{"prompt":"I have been robbed!","expected":"I have been robbed","hint":"Reporting a robbery incident."},{"prompt":"Can you send a fire truck quickly?","expected":"Can you send a fire truck quickly","hint":"Request for fire emergency response."},{"prompt":"I need a doctor right away!","expected":"I need a doctor right away","hint":"Urgent medical request."},{"prompt":"There’s a gas leak in my apartment!","expected":"There’s a gas leak in my apartment","hint":"Reporting a gas emergency."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A1', 'reading', 'Modern Family', 'Read about a family with multiple pets.', '{"type":"read_and_choose","instructions":"Read the description and answer.","exercises":[{"sentence":"My brother has a large dog and two small cats. My sister has a bird.","question":"Who has the bird?","options":["The brother","The sister","The narrator"],"correct":1,"explanation":"The sister has a bird."},{"sentence":"The dog is brown, but the cats are white and black.","question":"What color is the dog?","options":["white","black","brown"],"correct":2,"explanation":"The dog is brown."},{"sentence":"We all live in a big house with a blue door.","question":"What color is the door?","options":["blue","green","red"],"correct":0,"explanation":"The door is blue."},{"sentence":"On Sundays, we walk in the park near the river.","question":"When do they walk?","options":["Fridays","Saturdays","Sundays"],"correct":2,"explanation":"Sundays."},{"sentence":"My parents love gardening and planting flowers.","question":"What do the parents do?","options":["Running","Gardening","Fishing"],"correct":1,"explanation":"They love gardening."},{"sentence":"My mother loves to bake cookies, and my father enjoys gardening.","question":"Who enjoys gardening?","options":["The mother","The father","The narrator"],"correct":1,"explanation":"The father enjoys gardening."},{"sentence":"The cat is sleeping on the couch while the dog is playing outside.","question":"Where is the cat?","options":["Outside","On the couch","In the garden"],"correct":1,"explanation":"The cat is sleeping on the couch."},{"sentence":"My friend has a bright yellow bicycle and a red helmet.","question":"What color is the bicycle?","options":["red","yellow","blue"],"correct":1,"explanation":"The bicycle is bright yellow."},{"sentence":"There are three flavors of ice cream: chocolate, vanilla, and strawberry.","question":"How many flavors of ice cream are there?","options":["Two","Three","Four"],"correct":1,"explanation":"There are three flavors of ice cream."},{"sentence":"The family went to the beach and built a sandcastle.","question":"What did the family build?","options":["A fort","A sandcastle","A house"],"correct":1,"explanation":"The family built a sandcastle."},{"sentence":"My uncle drives a blue car, and my aunt has a green one.","question":"What color is the uncle''s car?","options":["green","blue","red"],"correct":1,"explanation":"The uncle drives a blue car."},{"sentence":"The library is quiet, filled with books and comfortable chairs.","question":"What is the library filled with?","options":["Toys","Books","Computers"],"correct":1,"explanation":"The library is filled with books."},{"sentence":"The children played soccer in the park while the parents watched.","question":"Who played soccer?","options":["The parents","The children","The pets"],"correct":1,"explanation":"The children played soccer."},{"sentence":"I have a collection of stamps from different countries.","question":"What does the narrator collect?","options":["Coins","Stamps","Postcards"],"correct":1,"explanation":"The narrator has a collection of stamps."},{"sentence":"My grandmother knits sweaters, and my grandfather carves wood.","question":"Who knits sweaters?","options":["The grandmother","The grandfather","The narrator"],"correct":0,"explanation":"The grandmother knits sweaters."},{"sentence":"The sun was shining brightly while the birds were singing.","question":"What were the birds doing?","options":["Flying","Singing","Sleeping"],"correct":1,"explanation":"The birds were singing."},{"sentence":"There is a big tree in the backyard where we often have picnics.","question":"Where do they often have picnics?","options":["In the park","In the backyard","At the beach"],"correct":1,"explanation":"They often have picnics in the backyard."},{"sentence":"My sister plays the piano, and my brother plays the guitar.","question":"Who plays the piano?","options":["The sister","The brother","Both"],"correct":0,"explanation":"My sister plays the piano."},{"sentence":"The movie was exciting, and the popcorn was delicious.","question":"What was delicious?","options":["The movie","The popcorn","The soda"],"correct":1,"explanation":"The popcorn was delicious."},{"sentence":"My favorite season is autumn because of the colorful leaves.","question":"Which season is the narrator''s favorite?","options":["Winter","Spring","Autumn"],"correct":2,"explanation":"The narrator''s favorite season is autumn."}]}', 11),
('en', 'A1', 'reading', 'The Menu', 'Read a cafe menu and choose items.', '{"type":"read_and_choose","instructions":"Find the item on the menu.","exercises":[{"sentence":"Breakfast Special: Eggs and Toast - $5. Coffee/Tea - $2.","question":"How much is tea?","options":["$2","$5","$7"],"correct":0,"explanation":"Coffee/Tea is $2."},{"sentence":"Lunch: Chicken Sandwich ($6) or Tomato Soup ($4).","question":"Which is cheaper for lunch?","options":["Sandwich","Soup"],"correct":1,"explanation":"Soup is $4, sandwich is $6."},{"sentence":"Kids Meal: Pasta and Juice - $3. Free cookie with every meal!","question":"What comes free?","options":["Pasta","Juice","Cookie"],"correct":2,"explanation":"Free cookie with every meal."},{"sentence":"We are open from 8am to 8pm every day.","question":"Are they open at 7pm?","options":["Yes","No"],"correct":0,"explanation":"They are open until 8pm."},{"sentence":"Located at North Street, opposite the library.","question":"What is across the street?","options":["A bank","A library","A park"],"correct":1,"explanation":"Opposite the library."},{"sentence":"Dinner Menu: Grilled Salmon - $15. Side Salad - $5.","question":"How much is the side salad?","options":["$5","$15","$10"],"correct":0,"explanation":"The side salad is $5."},{"sentence":"Appetizers: Nachos ($6) or Spring Rolls ($4).","question":"Which appetizer is more expensive?","options":["Nachos","Spring Rolls"],"correct":0,"explanation":"Nachos cost $6, while spring rolls cost $4."},{"sentence":"Dessert: Chocolate Cake - $4. Ice Cream - $3.","question":"Which dessert costs less?","options":["Cake","Ice Cream"],"correct":1,"explanation":"Ice cream costs $3, while the cake costs $4."},{"sentence":"Beverages: Soda - $2. Lemonade - $3.","question":"How much is soda?","options":["$2","$3","$4"],"correct":0,"explanation":"Soda is priced at $2."},{"sentence":"Lunch Combo: Burger and Fries - $8. Drink - $2.","question":"What is the total cost of the lunch combo?","options":["$10","$8","$6"],"correct":0,"explanation":"The burger and fries cost $8 and the drink is $2, making a total of $10."},{"sentence":"Specials: Tacos ($8) or Burrito ($9).","question":"Which special is cheaper?","options":["Tacos","Burrito"],"correct":0,"explanation":"Tacos are $8, while the burrito is $9."},{"sentence":"Seafood Platter: Shrimp - $12. Crab Legs - $15.","question":"What is the cost of shrimp?","options":["$12","$15","$10"],"correct":0,"explanation":"Shrimp costs $12."},{"sentence":"Brunch: Pancakes - $7. Omelette - $8.","question":"Which is the more expensive brunch option?","options":["Pancakes","Omelette"],"correct":1,"explanation":"The omelette costs $8, while pancakes are $7."},{"sentence":"Smoothies: Berry Blast - $5. Tropical Twist - $6.","question":"Which smoothie is cheaper?","options":["Berry Blast","Tropical Twist"],"correct":0,"explanation":"Berry Blast is $5, while Tropical Twist is $6."},{"sentence":"Breakfast: Bagel - $2. Muffin - $3.","question":"How much does the muffin cost?","options":["$2","$3","$5"],"correct":1,"explanation":"The muffin costs $3."},{"sentence":"Salads: Caesar Salad - $7. Greek Salad - $6.","question":"Which salad is more affordable?","options":["Caesar Salad","Greek Salad"],"correct":1,"explanation":"Greek Salad is $6, while Caesar Salad is $7."},{"sentence":"Pasta Dishes: Spaghetti - $10. Fettuccine - $12.","question":"What is the price of fettuccine?","options":["$10","$12","$15"],"correct":1,"explanation":"Fettuccine costs $12."},{"sentence":"Coffees: Espresso - $3. Latte - $4.","question":"Which coffee costs more?","options":["Espresso","Latte"],"correct":1,"explanation":"Latte is $4, while espresso is $3."},{"sentence":"Pizza: Margherita - $10. Pepperoni - $12.","question":"What is the price of the Margherita pizza?","options":["$10","$12","$8"],"correct":0,"explanation":"Margherita pizza costs $10."},{"sentence":"Wraps: Chicken Wrap - $7. Veggie Wrap - $6.","question":"Which wrap is cheaper?","options":["Chicken Wrap","Veggie Wrap"],"correct":1,"explanation":"Veggie Wrap costs $6, while Chicken Wrap costs $7."}]}', 12),
('en', 'A1', 'reading', 'My Hobby: Photography', 'Read about taking photos.', '{"type":"read_and_choose","instructions":"Read and understand the hobby.","exercises":[{"sentence":"I take my camera everywhere I go. I love taking photos of nature.","question":"What does the person photograph?","options":["Buildings","Nature","People"],"correct":1,"explanation":"They love taking photos of nature."},{"sentence":"Sunset is the best time for beautiful pictures.","question":"When is the best time?","options":["Morning","Noon","Sunset"],"correct":2,"explanation":"Sunset is the best time."},{"sentence":"I have a digital camera, not an old film camera.","question":"What type of camera is it?","options":["Digital","Film"],"correct":0,"explanation":"It is a digital camera."},{"sentence":"Next month, I will have an exhibition at the local gallery.","question":"Where is the exhibition?","options":["Museum","Gallery","School"],"correct":1,"explanation":"At the local gallery."},{"sentence":"My friend Mark is a professional photographer too.","question":"Is Mark a photographer?","options":["Yes","No"],"correct":0,"explanation":"Mark is a professional photographer."},{"sentence":"I enjoy knitting sweaters for my friends and family.","question":"What does the person knit?","options":["Hats","Socks","Sweaters"],"correct":2,"explanation":"They enjoy knitting sweaters."},{"sentence":"Every Saturday, I go to the local farmer''s market to buy fresh vegetables.","question":"Where does the person buy vegetables?","options":["Grocery store","Local farmer''s market","Online"],"correct":1,"explanation":"They go to the local farmer''s market."},{"sentence":"I love to play chess with my grandfather during the weekends.","question":"Who does the person play chess with?","options":["Friends","Grandfather","Siblings"],"correct":1,"explanation":"They play chess with their grandfather."},{"sentence":"Gardening is my favorite hobby because I enjoy growing flowers.","question":"What does the person grow?","options":["Vegetables","Flowers","Fruits"],"correct":1,"explanation":"They enjoy growing flowers."},{"sentence":"I spend hours reading mystery novels every night.","question":"What kind of novels does the person read?","options":["Romance novels","Science fiction novels","Mystery novels"],"correct":2,"explanation":"They read mystery novels."},{"sentence":"I like to go hiking in the mountains during the summer.","question":"When does the person go hiking?","options":["Winter","Summer","Fall"],"correct":1,"explanation":"They go hiking in the summer."},{"sentence":"Cooking new recipes is a fun way to spend my free time.","question":"What does the person enjoy doing?","options":["Watching TV","Cooking new recipes","Playing video games"],"correct":1,"explanation":"They enjoy cooking new recipes."},{"sentence":"I practice yoga every morning to stay fit and relaxed.","question":"What does the person practice?","options":["Meditation","Yoga","Gymnastics"],"correct":1,"explanation":"They practice yoga."},{"sentence":"I collect stamps from different countries around the world.","question":"What does the person collect?","options":["Coins","Stamps","Postcards"],"correct":1,"explanation":"They collect stamps."},{"sentence":"I enjoy painting landscapes in my free time.","question":"What does the person paint?","options":["Portraits","Landscapes","Abstract art"],"correct":1,"explanation":"They enjoy painting landscapes."},{"sentence":"I love to play the guitar and write my own songs.","question":"What instrument does the person play?","options":["Piano","Drums","Guitar"],"correct":2,"explanation":"They play the guitar."},{"sentence":"I often go cycling along the river in the evenings.","question":"Where does the person go cycling?","options":["In the park","Along the river","In the mountains"],"correct":1,"explanation":"They go cycling along the river."},{"sentence":"Photography allows me to capture beautiful moments.","question":"What hobby does the person enjoy?","options":["Drawing","Photography","Writing"],"correct":1,"explanation":"They enjoy photography."},{"sentence":"I enjoy birdwatching and identifying different species.","question":"What activity does the person enjoy?","options":["Fishing","Birdwatching","Hiking"],"correct":1,"explanation":"They enjoy birdwatching."},{"sentence":"I often write poetry to express my feelings.","question":"What does the person write?","options":["Novels","Short stories","Poetry"],"correct":2,"explanation":"They write poetry."}]}', 13),
('en', 'A1', 'reading', 'Email to a Friend', 'A short email from a vacation.', '{"type":"read_and_choose","instructions":"Understand the email content.","exercises":[{"sentence":"Hi Tom, I am in Spain right now! The weather is very hot and sunny.","question":"Where is the sender?","options":["Italy","Spain","France"],"correct":1,"explanation":"I am in Spain."},{"sentence":"Yesterday, I visited a famous museum in the center of the city.","question":"What did they visit?","options":["A park","A museum","A beach"],"correct":1,"explanation":"Visited a museum."},{"sentence":"I am eating a lot of seafood and drinking cold orange juice.","question":"What are they eating?","options":["Steak","Seafood","Pasta"],"correct":1,"explanation":"Eating a lot of seafood."},{"sentence":"I am coming home next Saturday on the evening flight.","question":"When are they coming home?","options":["Friday","Saturday","Sunday"],"correct":1,"explanation":"Next Saturday."},{"sentence":"See you soon, Anna.","question":"Who wrote the email?","options":["Tom","Anna","Mark"],"correct":1,"explanation":"Anna wrote it."},{"sentence":"I went hiking in the mountains last weekend. The views were breathtaking!","question":"What activity did they do?","options":["Hiking","Swimming","Cycling"],"correct":0,"explanation":"Went hiking in the mountains."},{"sentence":"I tried some delicious local dishes at a restaurant in the city.","question":"What did they try?","options":["Local dishes","Fast food","Desserts"],"correct":0,"explanation":"Tried some delicious local dishes."},{"sentence":"My friends and I are planning a road trip next month.","question":"What are they planning?","options":["A flight","A road trip","A train journey"],"correct":1,"explanation":"Planning a road trip."},{"sentence":"I bought souvenirs for my family from the market.","question":"What did they buy?","options":["Food","Souvenirs","Clothes"],"correct":1,"explanation":"Bought souvenirs from the market."},{"sentence":"The hotel I stayed in was very comfortable and had a beautiful view.","question":"How was the hotel?","options":["Uncomfortable","Comfortable","Average"],"correct":1,"explanation":"The hotel was very comfortable."},{"sentence":"I attended a concert in the park last night. It was amazing!","question":"What event did they attend?","options":["A concert","A play","A sports game"],"correct":0,"explanation":"Attended a concert in the park."},{"sentence":"I visited my cousin who lives in a different country.","question":"Who did they visit?","options":["A friend","A cousin","A sibling"],"correct":1,"explanation":"Visited my cousin."},{"sentence":"We watched the sunset on the beach and it was beautiful.","question":"What did they watch?","options":["The sunrise","The sunset","The stars"],"correct":1,"explanation":"Watched the sunset on the beach."},{"sentence":"I love to explore new places and meet new people.","question":"What do they love to do?","options":["Stay at home","Explore new places","Watch TV"],"correct":1,"explanation":"Love to explore new places."},{"sentence":"I took many photos during my vacation to capture the memories.","question":"What did they do with their vacation?","options":["Captured memories","Lost memories","Forgot memories"],"correct":0,"explanation":"Captured the memories with photos."},{"sentence":"We went to a festival and enjoyed live music and dancing.","question":"What did they enjoy at the festival?","options":["Food and drinks","Live music and dancing","Art and crafts"],"correct":1,"explanation":"Enjoyed live music and dancing."},{"sentence":"I spent the day relaxing by the pool with a good book.","question":"What did they do by the pool?","options":["Swim","Relax and read","Play games"],"correct":1,"explanation":"Relaxed by the pool with a good book."},{"sentence":"I visited the historical sites in the city and learned a lot.","question":"What did they visit?","options":["Shopping malls","Historical sites","Restaurants"],"correct":1,"explanation":"Visited historical sites in the city."},{"sentence":"I enjoyed a lovely dinner at a rooftop restaurant with a view.","question":"Where did they have dinner?","options":["At home","At a rooftop restaurant","In a park"],"correct":1,"explanation":"Had dinner at a rooftop restaurant."},{"sentence":"I went to a local market to buy fresh fruits and vegetables.","question":"What did they buy at the market?","options":["Fresh fruits and vegetables","Clothing","Toys"],"correct":0,"explanation":"Bought fresh fruits and vegetables."}]}', 14),
('en', 'A1', 'reading', 'Job Advertisement', 'Basic job requirements.', '{"type":"read_and_choose","instructions":"Find info in the ad.","exercises":[{"sentence":"Wanted: Part-time waiter for a busy Italian restaurant.","question":"What is the job?","options":["Cook","Waiter","Manager"],"correct":1,"explanation":"Wanted: Part-time waiter."},{"sentence":"Hours: 6pm to 11pm, Thursday to Sunday.","question":"Do you work on Mondays?","options":["Yes","No"],"correct":1,"explanation":"Thursday to Sunday."},{"sentence":"Experience: Not required, but helpful. We provide training.","question":"Do you need experience?","options":["Yes","No"],"correct":1,"explanation":"Not required."},{"sentence":"Pay: $12 per hour plus tips.","question":"What is the hourly rate?","options":["$10","$12","$15"],"correct":1,"explanation":"$12 per hour."},{"sentence":"Call 555-0199 to apply. Ask for Maria.","question":"Who should you ask for?","options":["John","Maria","Sarah"],"correct":1,"explanation":"Ask for Maria."},{"sentence":"Looking for a full-time graphic designer for a marketing agency.","question":"What is the job type?","options":["Part-time","Full-time","Intern"],"correct":1,"explanation":"Looking for a full-time graphic designer."},{"sentence":"Salary: $40,000 per year with benefits.","question":"Is there a salary mentioned?","options":["Yes","No"],"correct":0,"explanation":"Salary: $40,000 per year."},{"sentence":"Location: Downtown office, accessible by public transport.","question":"Is the office location convenient?","options":["Yes","No"],"correct":0,"explanation":"Accessible by public transport."},{"sentence":"Skills: Proficient in Adobe Creative Suite and teamwork.","question":"Do you need to know Adobe Creative Suite?","options":["Yes","No"],"correct":0,"explanation":"Proficient in Adobe Creative Suite."},{"sentence":"Job starts immediately for the right candidate.","question":"When does the job start?","options":["Next month","Immediately"],"correct":1,"explanation":"Job starts immediately."},{"sentence":"Contact: Email your resume to hr@company.com.","question":"How do you apply for the job?","options":["By phone","In person","By email"],"correct":2,"explanation":"Email your resume to hr@company.com."},{"sentence":"Requirements: Bachelor’s degree in design or related field.","question":"Is a degree required?","options":["Yes","No"],"correct":0,"explanation":"Bachelor’s degree in design or related field."},{"sentence":"Work environment: Collaborative and creative.","question":"What is the work environment like?","options":["Isolated","Collaborative"],"correct":1,"explanation":"Collaborative and creative."},{"sentence":"Benefits include health insurance and paid time off.","question":"Are there benefits?","options":["Yes","No"],"correct":0,"explanation":"Benefits include health insurance and paid time off."},{"sentence":"Deadline for applications: March 15th.","question":"When is the application deadline?","options":["March 15th","April 1st"],"correct":0,"explanation":"Deadline for applications: March 15th."},{"sentence":"Team events and outings are organized regularly.","question":"Are team events held?","options":["Yes","No"],"correct":0,"explanation":"Team events and outings are organized regularly."},{"sentence":"Position available for a motivated self-starter.","question":"What type of person are they looking for?","options":["Motivated","Unmotivated"],"correct":0,"explanation":"Position available for a motivated self-starter."},{"sentence":"Previous work samples are required for review.","question":"Do you need to provide work samples?","options":["Yes","No"],"correct":0,"explanation":"Previous work samples are required for review."},{"sentence":"Flexible hours available after training period.","question":"Are hours flexible?","options":["Yes","No"],"correct":0,"explanation":"Flexible hours available after training period."},{"sentence":"Training provided for new hires.","question":"Is there training for new employees?","options":["Yes","No"],"correct":0,"explanation":"Training provided for new hires."}]}', 15);
INSERT INTO lessons (language_code, cefr_level, skill, title, description, content, order_index) VALUES
('en', 'A1', 'writing', 'Pronoun Power', 'Build sentences with correct pronouns.', '{"type":"type_word","instructions":"Type the correct pronoun.","exercises":[{"prompt":"My brother is tall. [He/She] is a basketball player.","expected":"He","hint":"Brother is male."},{"prompt":"My sister and I are students. [We/They] go to school.","expected":"We","hint":"Includes the narrator."},{"prompt":"Look at those birds! [It/They] are flying south.","expected":"They","hint":"Plural animals."},{"prompt":"The cat is sleeping. [It/He] is very cute.","expected":"It","hint":"Neutral animal pronoun."},{"prompt":"John and Mary are married. [We/They] live in London.","expected":"They","hint":"Third person plural."},{"prompt":"Maria loves to read. [She/He] has many books.","expected":"She","hint":"Maria is female."},{"prompt":"The dog is barking. [It/They] want to go outside.","expected":"It","hint":"Singular animal."},{"prompt":"John and I are going to the park. [We/They] will play soccer.","expected":"We","hint":"Includes the narrator."},{"prompt":"The children are laughing. [They/It] are having fun.","expected":"They","hint":"Plural group of kids."},{"prompt":"This is my friend, Alex. [He/She] is a great musician.","expected":"He","hint":"Alex is male."},{"prompt":"The cat is sleeping. [It/They] looks very comfortable.","expected":"It","hint":"Singular animal."},{"prompt":"Lisa and her sister are artists. [They/We] create beautiful paintings.","expected":"They","hint":"Referring to two people."},{"prompt":"My parents are at home. [They/We] are cooking dinner.","expected":"They","hint":"Referring to multiple people."},{"prompt":"This book is interesting. [It/They] has many facts.","expected":"It","hint":"Referring to a singular object."},{"prompt":"My best friend is coming over. [She/He] is bringing snacks.","expected":"She","hint":"Friend is female."},{"prompt":"The trees are swaying in the wind. [They/It] look beautiful.","expected":"They","hint":"Plural objects."},{"prompt":"My sister loves ice cream. [She/He] eats it every day.","expected":"She","hint":"Sister is female."},{"prompt":"The computer is running slow. [It/They] needs an update.","expected":"It","hint":"Referring to a singular object."},{"prompt":"Tom and Jerry are friends. [They/It] play together every day.","expected":"They","hint":"Referring to two characters."},{"prompt":"The baby is crying. [He/It] needs to be fed.","expected":"He","hint":"Baby is male."}]}', 11),
('en', 'A1', 'writing', 'Plural Fun', 'Change words from singular to plural.', '{"type":"type_word","instructions":"Type the plural form.","exercises":[{"prompt":"One dog, two...","expected":"dogs","hint":"Just add -s."},{"prompt":"One city, two...","expected":"cities","hint":"-y becomes -ies."},{"prompt":"One child, two...","expected":"children","hint":"Irregular plural."},{"prompt":"One man, two...","expected":"men","hint":"Vowel change."},{"prompt":"One apple, two...","expected":"apples","hint":"Add -s."},{"prompt":"One tooth, two...","expected":"teeth","hint":"Irregular plural."},{"prompt":"One baby, two...","expected":"babies","hint":"-y becomes -ies."},{"prompt":"One leaf, two...","expected":"leaves","hint":"-f becomes -ves."},{"prompt":"One mouse, two...","expected":"mice","hint":"Irregular plural."},{"prompt":"One person, two...","expected":"people","hint":"Irregular plural."},{"prompt":"One cactus, two...","expected":"cacti","hint":"Latin irregular plural."},{"prompt":"One ox, two...","expected":"oxen","hint":"Irregular plural."},{"prompt":"One box, two...","expected":"boxes","hint":"-x becomes -es."},{"prompt":"One church, two...","expected":"churches","hint":"-ch becomes -es."},{"prompt":"One quiz, two...","expected":"quizzes","hint":"-z becomes -zes."},{"prompt":"One woman, two...","expected":"women","hint":"Irregular plural."},{"prompt":"One criterion, two...","expected":"criteria","hint":"Greek irregular plural."},{"prompt":"One analysis, two...","expected":"analyses","hint":"-is becomes -es."},{"prompt":"One phenomenon, two...","expected":"phenomena","hint":"Greek irregular plural."},{"prompt":"One thesis, two...","expected":"theses","hint":"-is becomes -es."}]}', 12),
('en', 'A1', 'writing', 'Daily Objects', 'Type names of common things.', '{"type":"type_word","instructions":"Type the object name.","exercises":[{"prompt":"You use this to open a door.","expected":"key","hint":"Small metal object."},{"prompt":"You use this to call people.","expected":"phone","hint":"Electronic device."},{"prompt":"You use this to umbrella.","expected":"umbrella","hint":"Protects from rain."},{"prompt":"You wear this on your wrist to see time.","expected":"watch","hint":"Small clock."},{"prompt":"You sit on this.","expected":"chair","hint":"Furniture."},{"prompt":"You use this to write on paper.","expected":"pen","hint":"Ink-filled writing tool."},{"prompt":"You use this to take photographs.","expected":"camera","hint":"Device for capturing images."},{"prompt":"You use this to cut paper.","expected":"scissors","hint":"Tool with two blades."},{"prompt":"You use this to listen to music.","expected":"headphones","hint":"Worn over or in your ears."},{"prompt":"You use this to carry books.","expected":"backpack","hint":"Worn on your back."},{"prompt":"You use this to eat soup.","expected":"spoon","hint":"Round utensil."},{"prompt":"You use this to keep warm.","expected":"blanket","hint":"Soft covering for warmth."},{"prompt":"You use this to clean your teeth.","expected":"toothbrush","hint":"Small brush for dental hygiene."},{"prompt":"You use this to measure time.","expected":"watch","hint":"Worn on the wrist."},{"prompt":"You use this to boil water.","expected":"kettle","hint":"Container for heating water."},{"prompt":"You use this to see in the dark.","expected":"flashlight","hint":"Portable light source."},{"prompt":"You use this to write notes.","expected":"notebook","hint":"Collection of blank pages."},{"prompt":"You use this to slice bread.","expected":"knife","hint":"Sharp cutting tool."},{"prompt":"You use this to keep your drinks cold.","expected":"cooler","hint":"Insulated container."},{"prompt":"You use this to navigate.","expected":"map","hint":"Detailed representation of an area."}]}', 13),
('en', 'A1', 'writing', 'Adjective Order', 'Describe things properly.', '{"type":"type_word","instructions":"Arrange: color + noun.","exercises":[{"prompt":"A [red / car]","expected":"red car","hint":"Adjective first."},{"prompt":"A [big / house]","expected":"big house","hint":"Size first."},{"prompt":"A [blue / sky]","expected":"blue sky","hint":"Color first."},{"prompt":"A [tall / man]","expected":"tall man","hint":"Height adjective."},{"prompt":"A [sweet / apple]","expected":"sweet apple","hint":"Taste adjective."},{"prompt":"A [green / tree]","expected":"green tree","hint":"Color before noun."},{"prompt":"A [yellow / flower]","expected":"yellow flower","hint":"Adjective goes first."},{"prompt":"A [purple / grape]","expected":"purple grape","hint":"Color comes first."},{"prompt":"A [white / cat]","expected":"white cat","hint":"Adjective precedes noun."},{"prompt":"A [orange / sunset]","expected":"orange sunset","hint":"Color before the subject."},{"prompt":"A [pink / dress]","expected":"pink dress","hint":"Adjective is first."},{"prompt":"A [brown / bear]","expected":"brown bear","hint":"Place the color first."},{"prompt":"A [gray / cloud]","expected":"gray cloud","hint":"Adjective comes before noun."},{"prompt":"A [black / dog]","expected":"black dog","hint":"Color is the first word."},{"prompt":"A [golden / ring]","expected":"golden ring","hint":"Adjective goes before the noun."},{"prompt":"A [silver / car]","expected":"silver car","hint":"Adjective comes first."},{"prompt":"A [cyan / ocean]","expected":"cyan ocean","hint":"Color precedes noun."},{"prompt":"A [teal / sofa]","expected":"teal sofa","hint":"Adjective first."},{"prompt":"A [violet / dress]","expected":"violet dress","hint":"Color is the first word."},{"prompt":"A [magenta / wall]","expected":"magenta wall","hint":"Adjective before noun."}]}', 14),
